    /** City name (e.g. "Seattle", "London", "Tokyo"). */
    @query city: string,

    /** The date to compute sun times for (YYYY-MM-DD). Defaults to today. */
    @query date?: plainDate,
  ): SunTimesResult | CityNotFoundError;
}
